# Generated by openai (gpt-5.4)
# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request, Response
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST
import os

app = Flask(__name__)

REQUESTS_TOTAL = Counter(
    "http_requests_total",
    "HTTP requests",
    ["user_id", "session_id", "path", "method", "status"]
)

USER_PATH_COUNTERS = {}

def get_user_path_counter(user_id: str, path: str) -> Counter:
    key = (user_id, path)
    if key not in USER_PATH_COUNTERS:
        metric_name = f"http_requests_user_{sanitize_metric_part(user_id)}_path_{sanitize_metric_part(path)}_total"
        USER_PATH_COUNTERS[key] = Counter(
            metric_name,
            "HTTP requests for a specific user and path"
        )
    return USER_PATH_COUNTERS[key]

def sanitize_metric_part(value: str) -> str:
    sanitized = []
    for ch in value:
        if ch.isalnum():
            sanitized.append(ch.lower())
        else:
            sanitized.append("_")
    result = "".join(sanitized).strip("_")
    if not result:
        result = "unknown"
    if result[0].isdigit():
        result = f"v_{result}"
    return result

@app.after_request
def record_metrics(response):
    user_id = request.headers.get("X-User-Id", "anonymous")
    session_id = request.headers.get("X-Session-Id", "none")
    path = request.full_path.rstrip("?")
    REQUESTS_TOTAL.labels(
        user_id=user_id,
        session_id=session_id,
        path=path,
        method=request.method,
        status=str(response.status_code)
    ).inc()
    get_user_path_counter(user_id, path).inc()
    return response

@app.route("/")
def index():
    return {
        "message": "ok",
        "path": request.full_path.rstrip("?")
    }

@app.route("/items/<item_id>")
def item(item_id):
    return {
        "item_id": item_id,
        "path": request.full_path.rstrip("?")
    }

@app.route("/metrics")
def metrics():
    return Response(generate_latest(), mimetype=CONTENT_TYPE_LATEST)

if __name__ == "__main__":
    port = int(os.getenv("PORT", "8000"))
    app.run(host="0.0.0.0", port=port)